mapper.insert:
 INSERT INTO LETTNAUTHORINFO 
       ( AUTHOR_CODE
       , AUTHOR_NM
       , AUTHOR_DC
       , AUTHOR_CREAT_DE )
VALUES ( #{authorCode}
       , #{authorNm}
       , #{authorDc}
       , now())

mapper.update:
UPDATE LETTNAUTHORINFO 
   SET AUTHOR_NM=#{authorNm}
     , AUTHOR_DC=#{authorDc}
 WHERE AUTHOR_CODE=#{authorCode}

mapper.select:
SELECT AUTHOR_CODE as authorCode, AUTHOR_NM as authorNm, AUTHOR_DC as authorDc, AUTHOR_CREAT_DE as authorCreatDe
  FROM LETTNAUTHORINFO 
 WHERE AUTHOR_CODE=#{authorCode}
